+    local procedure PopulateFromSKUAndRelatedBOMs(BOMStructure: Codeunit "BOM Tree")
+    var
+        StockkeepingUnit: Record "Stockkeeping Unit";
+        Item: Record Item;
+        ProductionBOMHeader: Record "Production BOM Header";
+        Parent: Codeunit "BOM Node";
+        Child: Codeunit "BOM Node";
+    begin
+        StockkeepingUnit.SetFilter("Production BOM No.", '<>%1', '');
+        if StockkeepingUnit.FindSet() then
+            repeat
+                Item.SetLoadFields("No.", "Low-Level Code", "Production BOM No.");
+                if Item.Get(StockkeepingUnit."Item No.") then
+                    if Item."Production BOM No." <> StockkeepingUnit."Production BOM No." then begin
+                        ProductionBOMHeader.SetLoadFields("No.", "Low-Level Code", Status);
+                        if ProductionBOMHeader.Get(StockkeepingUnit."Production BOM No.") then
+                            if CheckSKUProductionBOMIsCertified(StockkeepingUnit."Production BOM No.", ProductionBOMHeader.Status) then begin
+                                Parent.CreateForItem(Item."No.", Item."Low-Level Code", LowLevelCodeParam);
+                                Child.CreateForProdBOM(ProductionBOMHeader."No.", ProductionBOMHeader."Low-Level Code", LowLevelCodeParam);
+
+                                AddChildToParent(BOMStructure, Parent, Child);
+
+                                Clear(Parent);
+                                Clear(Child);
+                            end;
+                    end;
+            until StockkeepingUnit.Next() = 0;
+    end;
+
+    local procedure CheckSKUProductionBOMIsCertified(ProductionBOMNo: Code[20]; BOMStatus: Enum "BOM Status"): Boolean
