+        VersionManagement: Codeunit VersionManagement;
+    begin
+        if BOMStatus = BOMStatus::Certified then
+            exit(true);
+
+        exit(VersionManagement.GetBOMVersion(ProductionBOMNo, WorkDate(), true) <> '');
+    end;
